import{_ as s,o as a,c as i,ag as t}from"./chunks/framework.CbQjVMS6.js";const m=JSON.parse('{"title":"Optimize Your 8XP Programs","description":"","frontmatter":{},"headers":[],"relativePath":"features/ti-basic-optimization.md","filePath":"features/ti-basic-optimization.md","lastUpdated":1774323326000}'),n={name:"features/ti-basic-optimization.md"};function p(l,e,o,r,c,h){return a(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="optimize-your-8xp-programs" tabindex="-1">Optimize Your 8XP Programs <a class="header-anchor" href="#optimize-your-8xp-programs" aria-label="Permalink to &quot;Optimize Your 8XP Programs&quot;">​</a></h1><p><strong>Powerpack</strong> automatically optimizes your 8XP programs during processing, by removing unnecessary characters. Why?</p><ul><li><p>Keeps the file size small — essential for squeezing programs into the limited RAM space on the calculator</p></li><li><p>Keeps the programs running fast — smaller programs typically run faster</p></li></ul><hr><p>Here are the optimizations that Powerpack does:</p><ul><li><p>Removes comments and whitespace (spaces, tabs, extra line returns) — explained in detail <a href="/features/strip-comments">here</a></p></li><li><p>Removes all closing brackets, braces, and quotes, which are not necessary. For example:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">123*(456+7)→X</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{1,2,3}→⌊Y</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&quot;Hello&quot;→Str1</span></span></code></pre></div><p>Will become:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">123*(456+7→X</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{1,2,3→Y</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&quot;Hello→Str1</span></span></code></pre></div></li><li><p>Removes the list character (⌊) in situations where it’s optional</p></li><li><p>Replaces statements like <code>X=0</code> with <code>not(X</code> when they appear at the end of a line — they mean the same thing, but 1 byte less</p></li><li><p>Removes line returns following <code>DelVar</code> statements, which are not necessary</p></li></ul>`,6)])])}const u=s(n,[["render",p]]);export{m as __pageData,u as default};
